header {
  position: relative;
  z-index: 1;
  padding: 60px 48px 40px;
  border-bottom: 1px solid var(--border);
  display: flex;
  align-items: flex-end;
  justify-content: space-between;
  gap: 24px;
  flex-wrap: wrap;
}
.logo {
  font-family: 'Inter', sans-serif;
  font-size: 13px;
  letter-spacing: 0.08em;
  color: var(--accent);
  text-transform: uppercase;
}
h1 {
  font-family: 'Inter', sans-serif;
  font-size: clamp(42px, 6vw, 80px);
  font-weight: 400;
  line-height: 0.95;
  letter-spacing: -0.02em;
  color: var(--text);
}
h1 em {
  font-style: italic;
  color: var(--accent);
}
.header-meta {
  font-size: 11px;
  color: var(--muted);
  letter-spacing: 0.06em;
  text-transform: uppercase;
  text-align: right;
  line-height: 1.8;
}
.header-meta span {
  display: block;
}
.header-meta strong {
  color: var(--text);
  font-weight: 500;
}
.subhead {
  font-size: 11px;
  color: var(--muted);
  letter-spacing: 0.05em;
  margin-top: 16px;
  text-transform: uppercase;
}
/* Filter bar */
.filters {
  position: relative;
  z-index: 1;
  padding: 20px 48px;
  border-bottom: 1px solid var(--border);
  display: flex;
  gap: 8px;
  flex-wrap: wrap;
  align-items: center;
}
.filter-label {
  font-size: 10px;
  color: var(--muted);
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-right: 8px;
}
.filter-btn {
  background: var(--tag-bg);
  border: 1px solid var(--border);
  color: var(--muted);
  font-family: 'Inter', sans-serif;
  font-size: 10px;
  letter-spacing: 0.05em;
  padding: 6px 14px;
  cursor: pointer;
  transition: all 0.15s;
  text-transform: uppercase;
}
.filter-btn:hover, .filter-btn.active {
  background: var(--accent-dim);
  border-color: var(--accent);
  color: var(--accent);
}
/* Count */
.count-bar {
  position: relative;
  z-index: 1;
  padding: 14px 48px;
  border-bottom: 1px solid var(--border);
